<template>
    <component :is="currComponent" :props="props" @update="update" />
  </template>
  
  <script>
//   import { defineAsyncComponent } from 'vue'
  
  import AdminInterface from './tools/AdminInterface.vue'
//   import AdminInterfaces from 'src/components/admin/tools/AdminInterfaces.vue'
  import AdminImage from './tools/AdminImage.vue'
  import AdminImages from './tools/AdminImages.vue'
  import AdminOptions from './tools/AdminOptions.vue'
  import AdminBoolean from './tools/AdminBoolean.vue'
  
  
  // Dynamically import all .vue files from the components path
  const componentMap = {
    AdminInterface,
    // AdminInterfaces,
    AdminImage,
    AdminImages,
    AdminOptions,
    AdminBoolean
  }
  
  export default {
    name: 'ModelCell',
    props: {
      props: {
        type: Object,
        required: true
      },
      component: {
        type: String,
        required: true
      }
    },
    components: {
      ...componentMap
    },
    computed: {
      currComponent() {
        return componentMap[this.component]
      },
    },
    methods: {
      update(payload) {
        this.$emit('update', payload)
      }
    }
  }
  </script>
